    @staticmethod
    def _xml_escape(value):
        """
        Escape special XML characters to prevent XML injection.

        Args:
            value: String value to escape

        Returns:
            Escaped string safe for XML inclusion
        """
        if value is None:
            return ""
        value = str(value)
        value = value.replace("&", "&amp;")
        value = value.replace("<", "&lt;")
        value = value.replace(">", "&gt;")
        value = value.replace('"', "&quot;")
        value = value.replace("'", "&apos;")
        return value

    @staticmethod
    def decode_saml_response(encoded_response, is_deflated=False):
        """
        Decode a base64-encoded SAML response.

        Args:
            encoded_response: Base64-encoded SAML response string
            is_deflated: Whether the response is deflate-compressed

        Returns:
            Decoded XML string
        """
        decoded = base64.b64decode(encoded_response)

        if is_deflated:
            decoded = zlib.decompress(decoded, -15)

        return decoded.decode("utf-8")


